var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>스프리건 인자 안정화 완료…/</color>","JPN":"<color=#ffd34c>スプリガン因子の安定化完了……/</color>","ENG":"<color=#ffd34c>Spriggan Factor stabilized.../</color>","TWN":"<color=#ffd34c>守護者因子已穩定……/</color>","SCN":"<color=#ffd34c>守护者因子已稳定……/</color>","DEU":"<color=#ffd34c>Spriggan Factor stabilized.../</color>","FRA":"<color=#ffd34c>Spriggan Factor stabilized.../</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>인자 귀속 및 신체 동기화 개시…/</color>","JPN":"<color=#ffd34c>因子の帰属および身体同期化開始……/</color>","ENG":"<color=#ffd34c>Initiating Factor attribution and body synchronization.../</color>","TWN":"<color=#ffd34c>因子綁定與身體同步開始…… /</color>","SCN":"<color=#ffd34c>因子归属与身体同步开始…… /</color>","DEU":"<color=#ffd34c>Initiating Factor attribution and body synchronization.../</color>","FRA":"<color=#ffd34c>Initiating Factor attribution and body synchronization.../</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>인격 구성 완료… 사고 프로세스 활성화… 최초 접속 확인…/</color>","JPN":"<color=#ffd34c>人格の構成完了……思考プロセス活性化……初回接続確認……/</color>","ENG":"<color=#ffd34c>Personality construction complete... Thought process activated... First connection confirmed.../</color>","TWN":"<color=#ffd34c>人格構建完成……啟動思維程式……首次連接確認……/</color>","SCN":"<color=#ffd34c>人格构建完成……激活思维程序……首次连接确认……/</color>","DEU":"<color=#ffd34c>Personality construction complete... Thought process activated... First connection confirmed.../</color>","FRA":"<color=#ffd34c>Personality construction complete... Thought process activated... First connection confirmed.../</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"안녕, 셰퍼드.","JPN":"おはよう、シェパード。","ENG":"Hello, Shepherd.","TWN":"你好，牧羊犬。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"반갑구나. 내가 누군지 알아보겠니?","JPN":"初めまして、僕が誰か、わかるかい？","ENG":"A pleasure to meet you. Can you tell who I am?","TWN":"很高興見到你。你認得我是誰嗎？"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…응.","JPN":"……うん。","ENG":"...Yes.","TWN":"……嗯。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"당신은 나의 명령권자… 에드윈 프리하트.","JPN":"あなたはシェパードの命令権者……エッドウィン・プラハト。","ENG":"You are Shepherd's commander... Edwin Freeheart.","TWN":"你是我的指揮官……艾德溫·普立哈特。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"…그래.","JPN":"……そう。","ENG":"...Correct.","TWN":"……沒錯。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"새 몸에 적응할 때까지 쉬어두렴. 아픈 곳이 있으면 바로 나한테 말하고.","JPN":"新しい体に慣れるまで休みなさい。痛いところがあったらすぐ僕に話すんだ。","ENG":"Rest until you adjust into your new body. And tell me if it hurts anywhere.","TWN":"在你適應新的身體之前，好好休息吧。如果有哪裡不舒服，馬上告訴我。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"장장 한 달에 걸친 대시술이었어요. 무사히 깨어나서 다행이네요.","JPN":"一か月間の大施術でしたね。無事に目が覚めて安心しました。","ENG":"It was a month-long major surgery. I'm glad it all went well.","TWN":"這是長達一個月的大手術。我很高興她能安全醒來。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"이미 소실된 기억을 복원하는 데엔 실패했지만, 감수할만한 성과예요.","JPN":"すでに消えた記憶の復元には失敗しましたが、それでも素晴らしい成果です。","ENG":"Although we failed to restore the memories that were lost, it still is an achievement.","TWN":"雖然沒能恢復已經失去的記憶，但這是一個值得接受的結果。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"청동나무의 재생작업은 어떻게 되어가죠?","JPN":"青銅の木の再生作業はどうなっていますか？","ENG":"How is the restoration of the Bronze Tree going?","TWN":"青銅樹的再生作業進展如何？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"재생은 실패했습니다. 청동나무는 6일의 탄화 과정을 거쳐 수명을 다했어요.","JPN":"再生は失敗しました。青銅の木は6日間の炭化過程を経て寿命が尽きたんです。","ENG":"Restoration failed. The Bronze Tree died out after 6 days of carbonizing.","TWN":"再生失敗了。青銅樹在經過6天的碳化過程後就達到了其壽命的終點。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"정확히는 우리가 발견한 세계에 존재하는 청동나무가 수명을 다한 거죠.","JPN":"正確には、私たちが発見した世界に存在する全ての青銅の木の寿命が尽きました。","ENG":"To be exact, it's the lifespan of the Bronze Tree that existed in the world that we found reached its end.","TWN":"準確的說，我們世界中發現的青銅樹已經到了它的生命盡頭。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"몰랐어요. 셰퍼드의 심장에 스프리건 인자가 옮겨지자마자 청동나무가 시들어버릴 줄은…","JPN":"知らなかったんです。シェパードの心臓にスプリガン因子が移行してすぐ青銅の木が枯れてしまうなんて……","ENG":"I didn't know that the Bronze Tree would wither away as soon as we transferred the Spriggan Factor into Shepherd's heart...","TWN":"我沒想到，守護者因子一轉移到牧羊犬的心臟，青銅樹就枯萎了……"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"청동나무는 발견 당시에도 이미 죽어가고 있었습니다.","JPN":"青銅の木は発見当時からもすでに枯れかけていました。","ENG":"The Bronze Tree was already withering away when we discovered it.","TWN":"這棵青銅樹被發現時，它就已經快死了。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"하지만 우리가 셰퍼드를 통해 다시 한번 싹을 틔운 셈이니, 아쉬워할 필요는 없어요.","JPN":"しかし、私たちがシェパードを通じてもう一度芽生えさせたので、残念に思うことはありません。","ENG":"But through Shepherd, it has sprouted new seeds. So there is no need to feel sorry for it.","TWN":"不過，我們也不必感到遺憾，因為我們透過牧羊犬又重新讓新的種子開始發芽。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"아니, 오히려 이전보다 개선되었다고 봐야죠. 나무와 달리 셰퍼드에겐 사고능력이 있으니까요.","JPN":"いや、むしろ以前より改善されたと思うべきでしょう。木と違って、シェパードには思考能力がありますから。","ENG":"Rather, I see it as an improvement. Unlike the tree, Shepherd has cognitive abilities.","TWN":"不，它實際上比之前更加優秀。與樹木不同，牧羊犬擁有思考的能力。"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"음…?","JPN":"ん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"EDWIN_FLOOR_NULL_MASK","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RESEARCHER_FLOOR_UNION_ASSIST","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LAB","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"어머? 셰퍼드가 저희에게 손을 흔드네요.","JPN":"あら？　シェパードが私たちに手を振ってますよ。","ENG":"Oh? Shepherd is waving her hand at us.","TWN":"喔？牧羊犬正在向我們招手。"},"stage":{"bg":"LAB","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"아무래도 아이일 때의 인격이 남아있나 봐요.","JPN":"どうやら子どものころの人格が残ってるようですね。","ENG":"I guess some of her personality as a child remain intact.","TWN":"看來她還殘留著一些身為孩童的性格。"},"stage":{"bg":"LAB","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"<color=#ffd34c>남아있다</color>라…","JPN":"<color=#ffd34c>残ってる</color>、か……","ENG":"<color=#ffd34c>Remain intact</color>...","TWN":"<color=#ffd34c>殘留</color>嗎……"},"stage":{"bg":"LAB","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_MASK","text":{"KOREA":"잘 모르겠네요. 이게 정말 <color=#ffd34c>우리</color>가 진정으로 원하던 건지.","JPN":"よくわかりませんね。これが本当に<color=#ffd34c>僕たち</color>が望んでいたことなのか。","ENG":"I'm a little skeptical. Is this truly what <color=#ffd34c>we</color> wanted?","TWN":"我不知道。這真的是<color=#ffd34c>我們</color>想要的嗎？"},"stage":{"bg":"LAB","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RESEARCHER_FLOOR_UNION_ASSIST","text":{"KOREA":"물론 바라던 결과죠. <color=#ff3636>저희</color> 프로젝트는 한 아이의 영혼뿐만 아니라, 수많은 인명을 구해내는 일이니까요.","JPN":"当然望んだ結果でしょう。<color=#ff3636>私たち</color>のプロジェクトは一人の子どもの魂だけでなく、多くの人の命を救うことですから。","ENG":"Of course. Through this result, <color=#ff3636>our</color> project has not just saved a child's soul, but the rest of humanity as well.","TWN":"當然。<color=#ff3636>我們</color>的項目不僅要拯救一個孩子的靈魂，還要拯救無數的生命。"},"stage":{"bg":"LAB","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};